import './App.css';
import './Projects.css';
import NavBar from './NavBar';
import ProjectThumb from './ProjectThumb';
import React, {useState, useEffect} from 'react';
import { useLocation } from 'react-router-dom'
import {Link} from "react-router-dom"


function Projects(props) {
    useEffect(() => {
        document.title = props.title
    },[])

    const location = useLocation();
    const state = location.state;
    var categoryPassedIn = state["categoryPassedIn"]

    console.log("Cat Pass In: ",categoryPassedIn)
    if (!categoryPassedIn) {
        categoryPassedIn = "all";
        console.log("\tChanged to: ",categoryPassedIn)
    }
    var [category, setCategory] = useState(categoryPassedIn)

    function changeCategory(cat)  {
        console.log(cat)
        setCategory(cat)
    }

  return (
    <div>
      <NavBar page={"projects"}></NavBar>

        <div className="content-padding">

            <div className='splitDiv leftSplit'>
                <div id="projects-menu-fixed">
                    <div id="projects-menu-tablecell">
                        <div id="projects-menu-inner">
                            <p className={category==="all" ? "activeCategory":""} onClick={() => changeCategory("all")}>ALL</p>
                            <p className={category==="design" ? "activeCategory":""} onClick={() => changeCategory("design")}>DESIGN</p>
                            <p className={category==="engineering" ? "activeCategory":""} onClick={() => changeCategory("engineering")}>ENGINEERING</p>
                            <p className={category==="coding" ? "activeCategory":""} onClick={() => changeCategory("coding")}>CODING</p>
                            <p className={category==="interactive" ? "activeCategory":""} onClick={() => changeCategory("interactive")}>INTERACTIVE</p>
                            <p className={category==="graphic design"  ? "activeCategory":""} onClick={() => changeCategory("graphic design")}>GRAPHIC DESIGN</p>
                            <br></br>
                            {/* TODO LINK THIS */}
                            <p onClick={() => changeCategory("archive")}>ARCHIVE</p>
                        </div>
                    </div>
                </div>
            </div>


            <div className='splitDiv rightSplit'>
            <br></br>

                <Link to="/projectpage1"
                    state={{ categoryPassedIn: "all" }}>
                        <ProjectThumb></ProjectThumb>
                </Link>
                <br></br>
                <br></br>
                <Link to="/projectpage2">Project Page #2</Link>

                <br></br>
                <br></br>
                <br></br> 
                <h1 className='PangramDisplay'>This is PangramDisplay </h1>

                <h1 className='PangramHeader'>This is PangramHeader </h1>
                <h1 className='PangramHeaderItalic'>This is PangramHeaderItalic </h1>

                <h1 className='PangramText'>This is PangramText </h1>
                <h1 className='PangramTextBold'>This is PangramTextBold </h1>

                <h1 className='PangramCompact'>This is PangramCompact </h1>


            </div>


        </div>
    </div>
  );
}

export default Projects;
